from __future__ import annotations

import time
import uuid
from datetime import datetime, timezone
from typing import Annotated, Literal

from fastapi import (
    Body,
    Depends,
    FastAPI,
    Header,
    HTTPException,
    Query,
    Request,
    Response,
)
from pydantic import BaseModel, Field

app = FastAPI(title="FastAPI Demo", version="0.2.0")


# -------- Common models --------
class HealthResponse(BaseModel):
    status: str = "ok"
    now: datetime


@app.get("/health", response_model=HealthResponse)
def health() -> HealthResponse:
    return HealthResponse(now=datetime.now(timezone.utc))


class EchoIn(BaseModel):
    message: str = Field(min_length=1, max_length=2000)


class EchoOut(BaseModel):
    echoed: str


@app.post("/echo", response_model=EchoOut)
def echo(payload: EchoIn) -> EchoOut:
    return EchoOut(echoed=payload.message)


# -------- Middleware: request id + basic timing --------
@app.middleware("http")
async def add_request_id_and_timing(request: Request, call_next):
    rid = request.headers.get("x-request-id") or str(uuid.uuid4())
    start = time.perf_counter()
    response: Response = await call_next(request)
    cost_ms = (time.perf_counter() - start) * 1000
    response.headers["x-request-id"] = rid
    response.headers["x-process-time-ms"] = f"{cost_ms:.2f}"
    return response


# -------- Simple API key auth dependency --------
# Demo-only: hard-coded key.
API_KEY = "demo-key"


def require_api_key(x_api_key: Annotated[str | None, Header()] = None) -> None:
    if x_api_key != API_KEY:
        raise HTTPException(status_code=401, detail="Invalid or missing API key")


# -------- Tiny in-memory CRUD demo (enhanced) --------
class ItemIn(BaseModel):
    name: str = Field(min_length=1, max_length=200)
    price: float = Field(gt=0)
    tags: list[str] = Field(default_factory=list, max_length=20)
    in_stock: bool = True


class ItemUpdate(BaseModel):
    name: str | None = Field(default=None, min_length=1, max_length=200)
    price: float | None = Field(default=None, gt=0)
    tags: list[str] | None = Field(default=None, max_length=20)
    in_stock: bool | None = None


class Item(ItemIn):
    id: int


class ItemListResponse(BaseModel):
    total: int
    items: list[Item]


_db: dict[int, Item] = {}
_next_id = 1


@app.post("/items", response_model=Item)
def create_item(payload: ItemIn) -> Item:
    global _next_id
    item = Item(id=_next_id, **payload.model_dump())
    _db[item.id] = item
    _next_id += 1
    return item


@app.get("/items/{item_id}", response_model=Item)
def get_item(item_id: int) -> Item:
    item = _db.get(item_id)
    if item is None:
        raise HTTPException(status_code=404, detail="Item not found")
    return item


@app.get("/items", response_model=ItemListResponse)
def list_items(
    q: Annotated[str | None, Query(description="Name contains (case-insensitive)")] = None,
    tag: Annotated[str | None, Query(description="Has a tag (exact match)")] = None,
    in_stock: Annotated[bool | None, Query(description="Filter by stock status")] = None,
    sort: Annotated[Literal["id", "price", "name"], Query()] = "id",
    order: Annotated[Literal["asc", "desc"], Query()] = "asc",
    offset: Annotated[int, Query(ge=0)] = 0,
    limit: Annotated[int, Query(ge=1, le=100)] = 20,
) -> ItemListResponse:
    items = list(_db.values())

    if q:
        ql = q.lower()
        items = [it for it in items if ql in it.name.lower()]
    if tag:
        items = [it for it in items if tag in it.tags]
    if in_stock is not None:
        items = [it for it in items if it.in_stock == in_stock]

    reverse = order == "desc"
    if sort == "id":
        items.sort(key=lambda x: x.id, reverse=reverse)
    elif sort == "price":
        items.sort(key=lambda x: x.price, reverse=reverse)
    else:
        items.sort(key=lambda x: x.name.lower(), reverse=reverse)

    total = len(items)
    items = items[offset : offset + limit]
    return ItemListResponse(total=total, items=items)


@app.patch("/items/{item_id}", response_model=Item)
def update_item(item_id: int, payload: ItemUpdate) -> Item:
    item = _db.get(item_id)
    if item is None:
        raise HTTPException(status_code=404, detail="Item not found")

    data = payload.model_dump(exclude_unset=True)
    updated = item.model_copy(update=data)
    _db[item_id] = updated
    return updated


@app.delete("/items/{item_id}", status_code=204)
def delete_item(item_id: int) -> Response:
    if item_id not in _db:
        raise HTTPException(status_code=404, detail="Item not found")
    del _db[item_id]
    return Response(status_code=204)


# -------- Protected endpoint demo --------
class SummaryResponse(BaseModel):
    total_items: int
    total_value: float


@app.get("/admin/summary", response_model=SummaryResponse, dependencies=[Depends(require_api_key)])
def admin_summary() -> SummaryResponse:
    items = list(_db.values())
    total_value = sum(it.price for it in items)
    return SummaryResponse(total_items=len(items), total_value=total_value)


# -------- Endpoint demonstrating headers + raw body --------
class WhoAmIResponse(BaseModel):
    user_agent: str | None
    request_id: str | None


@app.get("/whoami", response_model=WhoAmIResponse)
def whoami(request: Request) -> WhoAmIResponse:
    return WhoAmIResponse(
        user_agent=request.headers.get("user-agent"),
        request_id=request.headers.get("x-request-id"),
    )

